import hashlib
import modal
from fastapi import FastAPI, Request

app = modal.App("event-driven-pipeline")

queue = modal.Queue.from_name("pipeline-events", create_if_missing=True)
registry = modal.Dict.from_name("pipeline-registry", create_if_missing=True)
volume = modal.Volume.from_name("pipeline-artifacts", create_if_missing=True)

web_app = FastAPI()

@web_app.post("/submit")
async def submit(request: Request):
    body = await request.json()
    data = body.get("data", "")
    queue.put(data)

    current = registry.get("total_submitted", 0)
    registry["total_submitted"] = current + 1

    return {"status": "enqueued", "data": data}

@web_app.get("/status")
async def status():
    return {
        "total_submitted": registry.get("total_submitted", 0),
        "total_processed": registry.get("total_processed", 0)
    }

@app.function()
@modal.asgi_app()
def api():
    return web_app

@app.function(volumes={"/data": volume}, retries=2)
def process_item(item: str):
    h = hashlib.sha256(item.encode()).hexdigest()
    with open(f"/data/{h}.txt", "w") as f:
        f.write(item)
    volume.commit()
    return h

@app.local_entrypoint()
def main():
    items = ["item1", "item2", "item3"]
    for item in items:
        queue.put(item)
        current_sub = registry.get("total_submitted", 0)
        registry["total_submitted"] = current_sub + 1

    for _ in range(3):
        item = queue.get()
        if item is not None:
            process_item.remote(item)
            current_proc = registry.get("total_processed", 0)
            registry["total_processed"] = current_proc + 1
